UPDATE artifact_processing
SET
  status = 'retry',
  meta = '{{ JSON.stringify($node["Send Artifact for Processing"].json.meta) }}'
WHERE artifact_id = {{ $node["Send Artifact for Processing"].json.artifact_id }}
  AND processor = '{{ $node["Send Artifact for Processing"].json.processor }}';

UPDATE artifact_processing
SET
  status = 'skip',
  meta = NULL
WHERE artifact_id = {{ $json.artifact_id }}
  AND processor = '{{ $('Set Processor').item.json.processor }}';
